-- 1. Seed roles
on conflict (role_key) do nothing;

-- 2. Seed organizations
on conflict (slug) do nothing;

-- 3. Seed agents
on conflict (id) do nothing;

-- 4. Seed policyholders (20 realistic ones)
on conflict (id) do nothing;

-- 5. Seed policies (30 across all statuses)
on conflict (policy_number) do nothing;

-- 6. Seed claims (15 claims against active policies)
on conflict (claim_number) do nothing;

-- 7. Seed claim payments for settled/closed claims

-- 8. Seed endorsements for active policies

-- 9. Seed coverages

-- Done!
select 'Seed complete! Counts:' as message;
select 'agents'       as table_name, count(*) from public.agents       union all
select 'policyholders',               count(*) from public.policyholders union all
select 'policies',                    count(*) from public.policies      union all
select 'claims',                      count(*) from public.claims        union all
select 'claim_payments',              count(*) from public.claim_payments union all
select 'endorsements',                count(*) from public.endorsements   union all
select 'coverages',                   count(*) from public.coverages;
